        {
            updated = false;
            return !string.IsNullOrEmpty(this.DisplayName);
        }

        public bool EvaluateDisplayName(DictionaryContextData contextData, IExecutionContext context, out bool updated)
        {
            updated = false;
            return !string.IsNullOrEmpty(this.DisplayName);
